import Area from '@/components/Area';
import { Environment, Text } from '@react-three/drei';
import { Canvas } from '@react-three/fiber';
import * as React from 'react';
import * as THREE from 'three';

export type Props = {};

function App01(props: Props) {
  const {} = props;

  const refText = React.useRef<THREE.Mesh>(null);

  React.useEffect(() => {
    if (!refText.current) return;

    console.log('refText.current', refText.current);
  }, []);

  return (
    <Area>
      {() => (
        <Canvas>
          <ambientLight />
          <pointLight position={[10, 10, 10]} />
          <directionalLight position={[0.0, 1.2, 3.86]} color={'#e7e2ca'} />
          <mesh>
            <boxGeometry args={[1, 1, 1]} />
            <meshStandardMaterial color="orange" />
          </mesh>
          <Environment preset={'apartment'} />
          <Text
            ref={(c: THREE.Mesh) => {
              refText.current = c;
            }}
            color="black"
            fontSize={1}
            position={[0, 0, 0]}
            anchorX="center"
            anchorY="middle"
          >
            Interactive Text Destruction
          </Text>
        </Canvas>
      )}
    </Area>
  );
}

export default React.memo(App01);
